    cursor: pointer;
}

.profile-widget-clear-image-button{
    border: 1px solid rgba(255, 109, 109, 0.35);
    background: rgba(255, 109, 109, 0.12);
    color: rgb(216, 86, 86);
    border-radius: 999px;
    padding: 0.24rem 0.6rem;
    font-size: 0.72rem;
    cursor: pointer;
}

.profile-widget-image{
    width: 100%;
    max-width: 340px;
    border-radius: 10px;
    object-fit: cover;
    margin-bottom: 0.4rem;
    border: 1px solid var(--border-light);
}

.profile-widget-image-wrapper{
    position: relative;
