    max-width: 340px;
}

.profile-widget-image-wrapper .profile-widget-image{
    margin-bottom: 0;
}

.profile-widget-image-resize-handle{
    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 10px;
    background: linear-gradient(transparent, rgba(0,0,0,0.15));
    border: none;
    border-bottom-left-radius: 10px;
    border-bottom-right-radius: 10px;
    cursor: ns-resize;
    opacity: 0;
    transition: opacity 0.15s ease;
}

.profile-widget-image-wrapper:hover .profile-widget-image-resize-handle{
